1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_MULTIPLIER = 1.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Step = QuoteStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	};
16	
17	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
18	
19	const roundUp = (n: number): number => Math.ceil(Math.round(n * 1e6) / 1e6);
20	
21	const itemPremium = (item: Item): number =>
22	  basePremium(item) * FIRST_INSURANCE_MULTIPLIER;
23	
24	const BLOCK_BASE = 60;
25	const COMPONENT_TYPES = new Set(["rune"]);
26	
27	const itemBaseTotal = (items: Item[]): number => {
28	  const componentCounts: Record<string, number> = {};
29	  let total = 0;
30	  for (const item of items) {
31	    if (COMPONENT_TYPES.has(item.type)) {
32	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
33	    } else {
34	      total += basePremium(item);
35	    }
36	  }
37	  for (const count of Object.values(componentCounts)) {
38	    total += count === 3 ? BLOCK_BASE : count * 25;
39	  }
40	  return total;
41	};
42	
43	const quotePremium = (items: Item[]): number => {
44	  const itemTotal = itemBaseTotal(items) * FIRST_INSURANCE_MULTIPLIER;
45	  return roundUp(itemTotal + PROCESSING_FEE);
46	};
47	
48	export const run = (scenario: Scenario): { results: { premium: number }[] } => {
49	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
50	  return { results };
51	};
